package org.alku.life_contract.mutation;
import com.lowdragmc.lowdraglib2.gui.texture.*;import com.lowdragmc.lowdraglib2.gui.ui.*;import com.lowdragmc.lowdraglib2.gui.ui.data.Horizontal;import com.lowdragmc.lowdraglib2.gui.ui.elements.*;import com.lowdragmc.lowdraglib2.gui.ui.event.HoverTooltips;import com.lowdragmc.lowdraglib2.gui.ui.event.UIEvents;import dev.vfyjxf.taffy.style.TaffyPosition;import net.minecraft.network.chat.Component;import net.minecraft.world.entity.player.Player;import org.alku.life_contract.NetworkHandler;
public final class MutationUi {public static final int WIDTH=430,HEIGHT=244;private static final IGuiTexture BG=GuiTextureGroup.of(new ColorRectTexture(0xF00E1519),new ColorBorderTexture(1,0xFFD7A928));private MutationUi(){}
 public static ModularUI create(MutationMenu m,Player p){UIElement root=new UIElement().layout(l->l.width(WIDTH).height(HEIGHT)).style(s->s.backgroundTexture(BG));label(root,"阵营异变树",12,7,180,14,0xFFFFD76A,12);label(root,"MP: "+m.points+"   已激活等级: "+m.total,230,8,185,12,0xFFF3E6B4,9);label(root,"T1 基础指令",20,28,110,12,0xFF76D5C8,9);label(root,"T2 进阶协议  ≥5",160,28,120,12,0xFFFFC857,9);label(root,"T3 终末天灾  ≥12",300,28,120,12,0xFFFF6B55,9);
 MutationNode[][] cols={{MutationNode.BLADE,MutationNode.ARMOR,MutationNode.NEST,MutationNode.MARK},{MutationNode.SWARM,MutationNode.BEHEMOTH,MutationNode.SENSE,MutationNode.PARASITE},{MutationNode.CALAMITY,MutationNode.PURIFICATION,MutationNode.AIRDROP}};for(int c=0;c<3;c++){int x=18+c*140;for(int r=0;r<cols[c].length;r++){MutationNode n=cols[c][r];int y=46+r*47;if(c<2&&r<cols[c].length-1)line(root,x+56,y+37,2,10);node(root,m,n,x,y);}}line(root,130,91,30,2);line(root,270,91,30,2);return ModularUI.of(UI.of(root),p);}
 private static void node(UIElement root,MutationMenu m,MutationNode n,int x,int y){int lv=m.levels.get(n),cost=n.costForNext(lv);boolean locked=m.total<n.requiredLevels()||(n.conflict()!=null&&m.levels.get(n.conflict())>0);Button b=new Button().setText(n.title+"  "+roman(lv)+"/"+roman(n.maxLevel())+"\n"+(cost<0?"已满级":locked?"未解锁":"消耗 "+cost+" MP + 升华"));b.layout(l->l.positionType(TaffyPosition.ABSOLUTE).left(x).top(y).width(116).height(37));b.style(s->s.backgroundTexture(GuiTextureGroup.of(new ColorRectTexture(locked?0xFF24282B:0xFF17282B),new ColorBorderTexture(1,locked?0xFF555555:0xFFD7A928))));b.textStyle(s->s.textColor(locked?0xFF888888:0xFFFFE59A).fontSize(7));b.setOnClick(e->NetworkHandler.CHANNEL.sendToServer(new MutationPackets.Upgrade(n)));b.addEventListener(UIEvents.HOVER_TOOLTIPS,e->e.hoverTooltips=HoverTooltips.empty().append(Component.literal(n.effect),Component.literal("每级消耗: "+costs(n))));root.addChild(b);}
 private static String costs(MutationNode n){StringBuilder b=new StringBuilder();for(int i=0;i<n.costs.length;i++){if(i>0)b.append(" / ");b.append("Lv").append(i+1).append(": ").append(n.costs[i]);}return b.toString();}
 private static void label(UIElement r,String t,int x,int y,int w,int h,int color,float size){Label l=new Label();l.setText(Component.literal(t));l.layout(a->a.positionType(TaffyPosition.ABSOLUTE).left(x).top(y).width(w).height(h));l.textStyle(s->s.textColor(color).fontSize(size).textAlignHorizontal(Horizontal.LEFT));l.setAllowHitTest(false);r.addChild(l);}private static void line(UIElement r,int x,int y,int w,int h){r.addChild(new UIElement().layout(l->l.positionType(TaffyPosition.ABSOLUTE).left(x).top(y).width(w).height(h)).style(s->s.backgroundTexture(new ColorRectTexture(0x99D7A928))).setAllowHitTest(false));}private static String roman(int n){return switch(n){case 1->"I";case 2->"II";case 3->"III";default->"0";};}}
